@udtf(returnType="id: int, value: string")
class MyUDTF:
    def eval(self, x: int):
        for i in range(x):
            yield (i, str(i))
spark.udtf.register("my_udtf", MyUDTF)

class ExplodeRange:
    def eval(self, n: int):
        for i in range(n):
            yield (i,)
spark.udtf.register("explode_range", ExplodeRange, returnType="idx: int")

class SumPartition:
    def __init__(self):
        self._sum = 0
    def eval(self, x: int):
        self._sum += x
    def terminate(self):
        yield (self._sum,)

from pyspark.sql.functions import pandas_udf, PandasUDFType
@pandas_udf("double", PandasUDFType.GROUPED_AGG)
def mean_udf(v: pd.Series) -> float:
    return v.mean()
df.groupBy("category").agg(mean_udf(col("value")))

from pyspark.sql.functions import pandas_udf
@pandas_udf("double")
def multiply(a: pd.Series, b: pd.Series) -> pd.Series:
    return a * b
df.select(multiply(col("x"), col("y")))

@pandas_udf(schema, PandasUDFType.GROUPED_MAP)
def normalize(pdf: pd.DataFrame) -> pd.DataFrame:
    pdf['value_norm'] = (pdf['value'] - pdf['value'].mean()) / pdf['value'].std()
    return pdf
df.groupBy("category").apply(normalize)

@pandas_udf("id long, value double")
def map_batches(iterator: Iterator[pd.DataFrame]) -> Iterator[pd.DataFrame]:
    for batch in iterator:
        batch['value'] = batch['value'] * 2
        yield batch
df.mapInPandas(map_batches, schema)

outer_var = 42
@udf(returnType=StringType())
def my_udf(x):
    return str(x + outer_var)  # captures closure variable

broadcast_data = sc.broadcast(large_dict)
@udf(returnType=StringType())
def lookup_udf(key):
    return broadcast_data.value.get(key, "unknown")
